import React, { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";

export default function AppraisalForm() {

  const navigate = useNavigate();
  const { id } = useParams();

  const employees = JSON.parse(localStorage.getItem("employees")) || [];
  const [appraisals, setAppraisals] =
    useState(JSON.parse(localStorage.getItem("appraisals")) || []);

  const [formData, setFormData] = useState({
    id: null,
    employeeName: "",
    department: "",
    period: "",
    rating: "",
    status: "Pending",
  });

  /* -------------------------
        LOAD EDIT DATA
  --------------------------*/
  useEffect(() => {
    if (!id) return;

    const record = appraisals.find(a => String(a.id) === String(id));

    if (record) {
      setFormData(record);
    }

  }, [id]);


  /* -------------------------
        HANDLE CHANGE
  --------------------------*/
  const handleChange = (e) => {
    const { name, value } = e.target;

    // Auto-set department when employee changes
    if (name === "employeeName") {
      const emp = employees.find(emp => emp.name === value);
      setFormData({
        ...formData,
        employeeName: value,
        department: emp ? emp.department : ""
      });
      return;
    }

    setFormData({
      ...formData,
      [name]: value
    });
  };


  /* -------------------------
        SAVE / UPDATE
  --------------------------*/
  const handleSubmit = (e) => {
    e.preventDefault();

    // Validation Rating
    if (formData.rating < 0 || formData.rating > 5) {
      alert("Rating must be between 0 and 5");
      return;
    }

    let updatedList;

    // EDIT MODE
    if (id) {
      updatedList = appraisals.map(a =>
        String(a.id) === String(id) ? formData : a
      );

      alert("Appraisal Updated Successfully");
    }

    // ADD MODE
    else {
      const newRecord = {
        ...formData,
        id: Date.now(),
      };

      updatedList = [...appraisals, newRecord];

      alert("Appraisal Added Successfully");
    }

    localStorage.setItem("appraisals", JSON.stringify(updatedList));
    navigate("/dashboard/appraisal");
  };


  return (
    <div style={{ padding: "25px" }}>

      <h2>
        {id ? "Edit Employee Appraisal" : "Add Employee Appraisal"}
      </h2>

      <form style={{ maxWidth: "500px", marginTop: "20px" }}
        onSubmit={handleSubmit}
      >

        {/* EMPLOYEE DROPDOWN */}
        <label>Employee Name</label>
        <select
          name="employeeName"
          value={formData.employeeName}
          onChange={handleChange}
          required
        >
          <option value="">Select Employee</option>

          {employees.map(emp => (
            <option key={emp.id} value={emp.name}>
              {emp.name}
            </option>
          ))}
        </select>

        {/* AUTO Department */}
        <label>Department</label>
        <input
          name="department"
          value={formData.department}
          disabled
        />

        <label>Review Period</label>
        <input
          name="period"
          value={formData.period}
          onChange={handleChange}
          placeholder="Jan 2024 - Dec 2024"
          required
        />

        <label>Rating (0 - 5)</label>
        <input
          type="number"
          step="0.1"
          name="rating"
          value={formData.rating}
          onChange={handleChange}
          required
        />

        <label>Status</label>
        <select
          name="status"
          value={formData.status}
          onChange={handleChange}
        >
          <option>Pending</option>
          <option>Approved</option>
          <option>Rejected</option>
        </select>

        <br /><br />

        <button type="submit" className="save-btn">
          Save
        </button>

        <button
          type="button"
          style={{ marginLeft: "10px" }}
          onClick={() => navigate("/dashboard/appraisal")}
        >
          Cancel
        </button>

      </form>
    </div>
  );
}
